import { API_URL, loginMessage, AuthContext, playSound } from './common.js';
import React, { useState, useContext } from 'react';
const Auth = ({ isOpen, close }) => {
  const { sessionAuth, setSessionAuth } = useContext(AuthContext);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState(null);
  const [loading, setLoading] = useState(false);
  const logUser = reg => {
    if (!username || !password) return playSound(0);
    setLoading(true);
    setMessage(null);
    fetch(`${API_URL}/ACCOUNT/LOGIN`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        username,
        password,
        reg
      })
    })
      .then(res => res.json())
      .then(res => {
        if (res.error) {
          setMessage(res.error);
          playSound(0);
        } else {
          setSessionAuth(res);
          setMessage('You are logged!');
          setPassword('');
          playSound(2);
          setTimeout(() => close(), 1000);
        }
      })
      .finally(() => setLoading(false));
  };
  return (
    isOpen && (
      <>
        {!loading ? (
          <p
            className="ui"
            style={{
              color: message && message !== loginMessage ? 'red' : 'limegreen',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              width: '100%',
              margin: 'auto auto',
              position: 'absolute',
              backgroundColor: 'transparent',
              border: 'none'
            }}
          >
            {message
              ? message
              : !sessionAuth
              ? `Please login or register!`
              : 'You are logged as ' + sessionAuth.data.username}
          </p>
        ) : null}
        <div className={'login'}>
          <button
            className="ui"
            style={{ position: 'absolute', left: 0, bottom: -50 }}
            onClick={close}
          >
            cancel
          </button>
          {!sessionAuth ? (
            <>
              <input
                onChange={e => setUsername(e.currentTarget.value)}
                className="ui bordered"
                placeholder="Username"
                style={{
                  color: 'white',
                  maxWidth: 300
                }}
              />
              <input
                onChange={e => setPassword(e.currentTarget.value)}
                className="ui bordered"
                placeholder="Password"
                type="password"
                style={{
                  color: 'white',
                  maxWidth: 300
                }}
                onKeyPress={e => e.key === 'Enter' && logUser()}
              />
              <p></p>

              <button className="ui" onClick={() => logUser()}>
                sign
              </button>

              <button className="ui" onClick={() => logUser(true)}>
                register
              </button>
            </>
          ) : (
            <button
              className="ui"
              onClick={() => {
                localStorage.removeItem('sessionTL');
                setSessionAuth(null);
                setMessage(`You are signed out!`);
                playSound(4);
              }}
            >
              logout
            </button>
          )}
        </div>
      </>
    )
  );
};
export default Auth;
