import {
  API_URL,
  playSound,
  elementsMap,
  AllNotes,
  sounds,
  hashCode,
  intToRGB,
  matrix,
  sound,
  clearAllTimeouts,
  AuthContext
} from './common.js';
import React, { useState, useEffect, useContext, useLayoutEffect } from 'react';
import Note from './Note.jsx';

function useWindowSize(initial) {
  const [size, setSize] = useState(initial);
  useLayoutEffect(() => {
    function updateSize() {
      setSize(Math.floor(window.innerWidth / 50));
    }
    window.addEventListener('resize', updateSize);
    updateSize();
    return () => window.removeEventListener('resize', updateSize);
  }, []);
  return size;
}

const Matrix = ({ openSession }) => {
  const [mod] = useState(15);
  const [width, setWidth] = useState(30);
  const [offset, setOffset] = useState(15);
  const [shift, setShift] = useState(0);
  const [volume, setVolume] = useState(30);
  const [Notes] = useState(AllNotes); //.slice(shift, offset + width)
  const [speed, setSpeed] = useState(0.25);
  const [pagination, setPagination] = useState(0);
  const [size, setSize] = useState(15);
  const [sheet, setSheet] = useState({});
  const [reload, setReload] = useState(true);
  const [load, setLoad] = useState(false);
  const [title, setTitle] = useState('');
  const [author, setAuthor] = useState('');
  const [authorPage, setAuthorPage] = useState(0);
  const [isMusicListOpen, setIsMusicListOpen] = useState(false);
  const [musicList, setMusicList] = useState([]);
  const { sessionAuth } = useContext(AuthContext);
  const resize = useWindowSize(width);
  const guardUnsighned = () => {
    if (!sessionAuth?.token) {
      openSession();
    } else {
      return true;
    }
  };

  useEffect(() => {
    setLoad(false);
    setWidth(resize);
    setLoad(true);
  }, [resize]);

  useEffect(() => {
    if (!sessionAuth) {
      return guardUnsighned();
    }

    const urlParams = new URLSearchParams(window.location.search);
    if (urlParams.has('title') && guardUnsighned()) {
      fetch(`${API_URL}/MUSIC/PIECE?title=${urlParams.get('title')}`, {
        method: 'GET',
        headers: {
          Authorization: 'Bearer ' + sessionAuth.token,
          'Content-Type': 'application/json'
        }
      })
        .then(res => res.json())
        .then(res => (!res.error ? addMusicFromList(res) : alert(res.error)));
    }
  }, [sessionAuth?.token]);

  useEffect(() => {
    setLoad(true);
  }, [reload]);

  const populateMusicList = ({ username, page, perPage }) => {
    setIsMusicListOpen(true);
    fetch(
      `${API_URL}/MUSIC/BY_AUTHOR?author=${username}&page=${page}&perPage=${perPage}`,
      {
        method: 'GET',
        headers: {
          Authorization: 'Bearer ' + sessionAuth.token,
          'Content-Type': 'application/json'
        }
      }
    )
      .then(res => res.json())
      .then(res => (!res.error ? setMusicList(res) : alert(res.error)));
  };

  const adjustVolume = volume => {
    sounds.forEach(s => (s.volume = volume / 100));
    setVolume(volume);
  };

  const addMusicFromList = current => {
    setLoad(false);
    setSpeed(current.speed);
    setOffset(current.offset);
    setShift(current.shift);
    setSheet(current.sheet);
    setIsMusicListOpen(false);
    callibrateNotes(current.sheet);
  };
  const callibrateNotes = sheet => {
    editMode();
    let pages = Math.floor(
      Object.values(sheet).reduce((acc, n) => (acc = Math.max(acc, n.x)), 0) /
        mod
    );
    const iteratePages = page => {
      setLoad(false);
      if (page <= pages) {
        setPagination(size * page);
        setTimeout(() => iteratePages(++page), 150);
      } else {
        setPagination(0);
      }
      setLoad(true);
    };
    iteratePages(0);
  };

  const offsetNotes = value => {
    setLoad(false);
    playSound(3);
    callibrateNotes(sheet);
    setReload(!reload);
  };

  const deleteNotes = title => {
    clearAllTimeouts();
    setSheet({});
    playSound(0);
    setPagination(0);
    setLoad(false);
    setReload(!reload);
    if (title.trim()) {
      fetch(`${API_URL}/MUSIC/REMOVE`, {
        method: 'DELETE',
        headers: {
          Authorization: 'Bearer ' + sessionAuth.token,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          title
        })
      });
    }
  };

  const playInterval = () => {
    let localMax = -Infinity;
    setTimeout(() => {
      if (size !== mod) setSize(mod);
      clearAllTimeouts();
      elementsMap.forEach(elem => {
        if (elem) {
          elem.style.opacity = '0.1';
        }
      });
      const sheetArr = Object.values(sheet).map(note => {
        const { x, y } = note;
        const element = elementsMap.get(`${(x + pagination) % mod}:${y}`);

        if (element) {
          element.style.opacity = '0.1';
          element.firstChild.style.transform = `scale(1)`;
        }
        localMax = Math.max(localMax, x);
        return { note, element, index: x };
      });

      for (let i = 0; i < localMax; i++) {
        if (!sheetArr[i]) {
          sheetArr[i] = { note: null, element: null, index: i };
        }
      }

      sheetArr.map(({ note, element, index }) =>
        setTimeout(() => {
          if (note) {
            const { value, delay } = note;
            sound.volume.value = volume - 30;
            sound.triggerAttackRelease(value, delay);

            if (element) {
              element.style.opacity = '1';
              element.firstChild.style.transform = `scale(${
                delay > 0.1 ? delay * 2 + 1.2 : 1.2
              })`;
            }
            setTimeout(() => {
              if (element) {
                element.style.opacity = '0.1';
                element.firstChild.style.transform = `scale(1)`;
              }
              index === localMax &&
                setTimeout(() => {
                  playInterval();
                }, 1000);
            }, 600);
          }
        }, speed * index * 1000 + 500)
      );
    }, 250);
  };

  const play = () => {
    if (pagination !== 0) {
      setPagination(0);
      setLoad(false);
      setReload(!reload);
    }
    playInterval();
  };

  const editMode = () => {
    setLoad(false);
    clearAllTimeouts();
    setReload(!reload);
  };

  return (
    <div>
      <div className="options">
        <div className="menu">
          <span className="ui label"> {'vol:'}</span>

          <input
            className="ui"
            onChange={e => {
              const amount = +e.currentTarget.value;
              if (amount >= 0 && amount <= 100) {
                adjustVolume(amount);
                playSound(5);
              }
            }}
            value={volume}
            type="number"
            min={0}
            max={100}
            style={{
              width: '50px',
              textAlign: 'center',
              fontSize: '20px'
            }}
          />
          <span className="ui label"> {'>>:'}</span>
          <input
            className="ui"
            onChange={e => {
              setShift(+e.currentTarget.value);
              playSound(5);
            }}
            value={shift}
            type="number"
            min={-AllNotes.length}
            max={AllNotes.length}
            style={{
              width: '50px',
              textAlign: 'center',
              fontSize: '20px'
            }}
          />
          <span className="ui label">{'<<:'}</span>
          <span className="ui label" onClick={() => offsetNotes(offset)}>
            ▷
          </span>
          <input
            className="ui"
            onChange={e => {
              const val = +e.currentTarget.value;
              setOffset(val);
            }}
            value={offset}
            type="number"
            min={0}
            max={AllNotes.length}
            style={{
              width: '50px',
              textAlign: 'center',
              fontSize: '20px'
            }}
          />
          <span className="ui label"> &#9716;</span>
          <input
            className="ui"
            onChange={e => playSound(5) || setSpeed(+e.currentTarget.value)}
            step="0.1"
            type="number"
            style={{
              width: 80,
              fontSize: 20,
              textAlign: 'center'
            }}
            value={speed}
          />
        </div>

        <div className="tools">
          <button onClick={play} className="ui">
            ▷
          </button>
          <button
            onClick={() => {
              editMode();
              playSound(1);
            }}
            className="ui"
            style={{
              fontSize: 35
            }}
          >
            &#9633;
          </button>

          <button
            onClick={() => {
              if (pagination <= 0) return;
              setLoad(false);
              setPagination(pagination - size);
              setReload(!reload);
              playSound(4);
            }}
            className="ui"
          >
            &#9650;
          </button>
          <button className="ui">{pagination / size}</button>
          <button
            onClick={e => {
              setLoad(false);
              setPagination(size + pagination);
              setReload(!reload);
              playSound(4);
            }}
            className="ui"
          >
            &#9660;
          </button>
          <span
            className="ui icon"
            style={{
              fontSize: '55px',
              margin: '0 15px'
            }}
            onClick={() => {
              if (!guardUnsighned()) return;
              if (isMusicListOpen) return setIsMusicListOpen(false);
              populateMusicList({
                username: author || sessionAuth.data.username,
                page: Math.floor(authorPage),
                perPage: 5
              });
            }}
          >
            &#9679;
          </span>
          <button
            className="ui"
            onClick={() => {
              if (!guardUnsighned()) return;
              fetch(`${API_URL}/MUSIC/INSERT`, {
                method: 'POST',
                headers: {
                  Authorization: 'Bearer ' + sessionAuth.token,
                  'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                  title,
                  sheet,
                  speed,
                  shift,
                  offset
                })
              })
                .then(() => playSound(2))
                .catch(() => playSound(0));
            }}
          >
            S
          </button>

          <input
            onChange={e => setTitle(e.currentTarget.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') {
                const toDelete = title.split('!');
                if (toDelete[0] === 'delete') {
                  deleteNotes(toDelete[1].trimStart());
                }
              }
            }}
            className="ui title"
            placeholder="Title"
          />
        </div>
      </div>
      {load && (
        <div
          className="matrix"
          style={{ gridTemplateColumns: 'auto '.repeat(width) }}
        >
          {matrix(mod, width, null).map((row, i) =>
            row.map((col, j) => (
              <Note
                i={i + pagination}
                j={j - shift}
                key={i + '-' + (j - shift)}
                note={Notes[j - shift + offset]}
                sound={sound}
                sheet={sheet}
                mod={mod}
                volume={volume}
              />
            ))
          )}
        </div>
      )}
      {isMusicListOpen && (
        <div className="collection">
          <input
            onChange={e => setAuthor(e.currentTarget.value)}
            onKeyPress={e =>
              e.key === 'Enter' &&
              populateMusicList({
                username: author || sessionAuth.data.username,
                page: Math.floor(authorPage),
                perPage: 5
              })
            }
            className="ui"
            placeholder="Author"
            value={author}
            style={{
              border: 'none',
              color: 'white'
            }}
          />

          <input
            className="ui"
            onChange={e => {
              setAuthorPage(+e.currentTarget.value);
              playSound(4);
              populateMusicList({
                username: author || sessionAuth.data.username,
                page: Math.floor(+e.currentTarget.value),
                perPage: 5
              });
            }}
            value={authorPage}
            type="number"
            min={0}
            style={{
              width: '50px',
              textAlign: 'center',
              fontSize: '35px',
              border: 'none'
            }}
          />
          <button
            className="ui"
            onClick={() => playSound(5) || setIsMusicListOpen(false)}
          >
            X
          </button>
          <hr
            style={{
              height: 1,
              border: 'none',
              backgroundColor: 'rgb(230, 30, 117)'
            }}
          />
          <div className="music-list">
            {musicList.map((music, index) => (
              <button
                className="ui music-pick"
                onMouseOver={() => playSound(1)}
                onClick={() => {
                  addMusicFromList(musicList[index]);
                  const urlParams = new URLSearchParams(window.location.search);
                  urlParams.set('title', musicList[index].title);
                  // eslint-disable-next-line no-restricted-globals
                  history.pushState({}, null, '?' + urlParams.toString());
                  playSound(6);
                }}
                key={music.title + '_' + index}
              >
                {music.title.split(sessionAuth.data.username + "'s")[1] ||
                  music.title}
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

export default Matrix;
